class Solution(object):
    def buddyStrings(self, s, goal):
        if len(s) != len(goal):
            return False
        if s == goal:
            return len(set(s)) < len(s)
        diff = [(i, s[i], goal[i]) for i in range(len(s)) if s[i] != goal[i]]
        return len(diff) == 2 and diff[0][1] == diff[1][2] and diff[0][2] == diff[1][1]
